/**
 * Atari 2600 Style Sprites
 * Blocky pixel art definitions for game objects
 * Each sprite is a 2D array where 1 = pixel on, 0 = pixel off
 *
 * Sprite data extracted from Atari 2600 sprite sheets using sprite-analyzer.html
 */
// Helper functions to flip sprites
function flipHorizontal(sprite) {
    return sprite.map(row => [...row].reverse());
}
function flipVertical(sprite) {
    return [...sprite].reverse();
}
function flipBoth(sprite) {
    return flipVertical(flipHorizontal(sprite));
}
